// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Counters.sol";
import "@openzeppelin/contracts/utils/math/SafeMath.sol";

/**
 * @title GovernanceModule
 * @dev Handles DAO governance with proposal creation and voting
 */
contract GovernanceModule is AccessControl {
    using Counters for Counters.Counter;
    using SafeMath for uint256;

    // Role definitions
    bytes32 public constant GOVERNOR_ROLE = keccak256("GOVERNOR_ROLE");

    // Proposal status
    enum ProposalStatus { Pending, Active, Succeeded, Executed, Defeated }

    // Vote type
    enum VoteType { Against, For, Abstain }

    // Proposal structure
    struct Proposal {
        uint256 id;
        address proposer;
        string description;
        uint256 startBlock;
        uint256 endBlock;
        uint256 forVotes;
        uint256 againstVotes;
        uint256 abstainVotes;
        bool executed;
        string ipfsHash; // For detailed proposal data
    }

    // State variables
    Counters.Counter private _proposalIds;
    mapping(uint256 => Proposal) public proposals;
    mapping(address => uint256) public votingPower; // In a real implementation, this would be based on token balance
    mapping(address => mapping(uint256 => bool)) public hasVoted;

    // Parameters
    uint256 public votingDelay = 1; // blocks
    uint256 public votingPeriod = 1000; // blocks (~1 day at 15s/block)
    uint256 public proposalThreshold = 1; // Minimum voting power needed to create a proposal

    // Events
    event ProposalCreated(
        uint256 indexed proposalId,
        address indexed proposer,
        string description,
        uint256 startBlock,
        uint256 endBlock,
        string ipfsHash
    );
    event VoteCast(
        address indexed voter,
        uint256 indexed proposalId,
        VoteType support,
        uint256 votes
    );
    event ProposalExecuted(uint256 indexed proposalId);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(GOVERNOR_ROLE, msg.sender);
    }

    /**
     * @dev Create a new governance proposal
     */
    function propose(
        string memory description,
        string memory ipfsHash
    ) external onlyRole(GOVERNOR_ROLE) returns (uint256) {
        require(
            votingPower[msg.sender] >= proposalThreshold,
            "Insufficient voting power"
        );

        _proposalIds.increment();
        uint256 proposalId = _proposalIds.current();

        Proposal storage newProposal = proposals[proposalId];
        newProposal.id = proposalId;
        newProposal.proposer = msg.sender;
        newProposal.description = description;
        newProposal.startBlock = block.number.add(votingDelay);
        newProposal.endBlock = block.number.add(votingPeriod);
        newProposal.ipfsHash = ipfsHash;

        emit ProposalCreated(
            proposalId,
            msg.sender,
            description,
            newProposal.startBlock,
            newProposal.endBlock,
            ipfsHash
        );

        return proposalId;
    }

    /**
     * @dev Cast a vote on a proposal
     */
    function castVote(
        uint256 proposalId,
        VoteType support
    ) external {
        require(votingPower[msg.sender] > 0, "No voting power");
        require(!hasVoted[msg.sender][proposalId], "Already voted");

        Proposal storage proposal = proposals[proposalId];
        require(proposal.id == proposalId, "Proposal does not exist");
        require(
            block.number >= proposal.startBlock &&
            block.number <= proposal.endBlock,
            "Voting period not active"
        );

        uint256 votes = votingPower[msg.sender];

        if (support == VoteType.For) {
            proposal.forVotes = proposal.forVotes.add(votes);
        } else if (support == VoteType.Against) {
            proposal.againstVotes = proposal.againstVotes.add(votes);
        } else if (support == VoteType.Abstain) {
            proposal.abstainVotes = proposal.abstainVotes.add(votes);
        }

        hasVoted[msg.sender][proposalId] = true;

        emit VoteCast(msg.sender, proposalId, support, votes);
    }

    /**
     * @dev Execute a successful proposal
     */
    function executeProposal(uint256 proposalId) external {
        Proposal storage proposal = proposals[proposalId];
        require(proposal.id == proposalId, "Proposal does not exist");
        require(block.number > proposal.endBlock, "Voting period not ended");
        require(!proposal.executed, "Proposal already executed");

        // Check if proposal passed
        bool passed = proposal.forVotes > proposal.againstVotes;
        require(passed, "Proposal did not pass");

        proposal.executed = true;

        // In a real implementation, you would execute the proposal's actions here
        // For example: call other contracts, update parameters, etc.

        emit ProposalExecuted(proposalId);
    }

    /**
     * @dev Get the current state of a proposal
     */
    function state(uint256 proposalId) external view returns (ProposalStatus) {
        require(_proposalIds.current() >= proposalId, "Proposal does not exist");

        Proposal storage proposal = proposals[proposalId];

        if (proposal.executed) {
            return ProposalStatus.Executed;
        } else if (block.number <= proposal.startBlock) {
            return ProposalStatus.Pending;
        } else if (block.number <= proposal.endBlock) {
            return ProposalStatus.Active;
        } else if (proposal.forVotes <= proposal.againstVotes) {
            return ProposalStatus.Defeated;
        } else {
            return ProposalStatus.Succeeded;
        }
    }

    /**
     * @dev Set voting parameters (only callable by admin)
     */
    function setVotingParameters(
        uint256 _votingDelay,
        uint256 _votingPeriod,
        uint256 _proposalThreshold
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        votingDelay = _votingDelay;
        votingPeriod = _votingPeriod;
        proposalThreshold = _proposalThreshold;
    }

    /**
     * @dev Grant voting power to an address (only callable by admin)
     */
    function setVotingPower(
        address account,
        uint256 power
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        votingPower[account] = power;
    }
}

contracts/IdentityRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";

/**
 * @title IdentityRegistry
 * @dev Manages decentralized identities and verifiable credentials for farmers and participants
 */
contract IdentityRegistry is AccessControl {
    using ECDSA for bytes32;

    // Role definitions
    bytes32 public constant ISSUER_ROLE = keccak256("ISSUER_ROLE");
    bytes32 public constant VERIFIER_ROLE = keccak256("VERIFIER_ROLE");

    // Credential types
    enum CredentialType {
        LAND_OWNERSHIP,
        CROP_HISTORY,
        CREDIT_HISTORY,
        KYC_VERIFICATION,
        OTHER
    }

    // Credential status
    enum CredentialStatus { ACTIVE, REVOKED, EXPIRED }

    // Verifiable Credential structure (simplified for MVP)
    struct VerifiableCredential {
        bytes32 id; // Unique identifier for the credential
        address subject; // DID of the credential subject
        CredentialType credType;
        string ipfsHash; // IPFS hash of the credential data
        address issuer; // DID of the issuer
        uint256 issuanceDate;
        uint256 expirationDate;
        CredentialStatus status;
    }

    // Decentralized Identity structure
    struct Identity {
        address owner;
        bool isActive;
        bytes32[] credentials; // Array of credential IDs
        mapping(bytes32 => bool) hasCredential; // Quick lookup for credentials
    }

    // State variables
    mapping(address => Identity) public identities;
    mapping(bytes32 => VerifiableCredential) public credentials;
    mapping(address => bool) public registeredDIDs;

    // Events
    event DIDRegistered(address indexed did, address owner);
    event CredentialIssued(
        bytes32 indexed credentialId,
        address indexed subject,
        CredentialType credType,
        address issuer
    );
    event CredentialRevoked(bytes32 indexed credentialId, address indexed issuer);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    /**
     * @dev Register a new decentralized identity (DID)
     */
    function registerDID() external {
        require(!registeredDIDs[msg.sender], "DID already registered");

        Identity storage identity = identities[msg.sender];
        identity.owner = msg.sender;
        identity.isActive = true;

        registeredDIDs[msg.sender] = true;

        emit DIDRegistered(msg.sender, msg.sender);
    }

    /**
     * @dev Issue a new verifiable credential
     */
    function issueCredential(
        address subject,
        CredentialType credType,
        string memory ipfsHash,
        uint256 validityPeriod
    ) external onlyRole(ISSUER_ROLE) returns (bytes32) {
        require(registeredDIDs[subject], "Subject DID not registered");

        bytes32 credentialId = keccak256(
            abi.encodePacked(
                subject,
                credType,
                block.timestamp,
                ipfsHash,
                msg.sender
            )
        );

        VerifiableCredential storage cred = credentials[credentialId];
        cred.id = credentialId;
        cred.subject = subject;
        cred.credType = credType;
        cred.ipfsHash = ipfsHash;
        cred.issuer = msg.sender;
        cred.issuanceDate = block.timestamp;
        cred.expirationDate = block.timestamp + validityPeriod;
        cred.status = CredentialStatus.ACTIVE;

        // Add to subject's identity
        Identity storage subjectIdentity = identities[subject];
        subjectIdentity.credentials.push(credentialId);
        subjectIdentity.hasCredential[credentialId] = true;

        emit CredentialIssued(credentialId, subject, credType, msg.sender);

        return credentialId;
    }

    /**
     * @dev Revoke a credential
     */
    function revokeCredential(bytes32 credentialId) external onlyRole(ISSUER_ROLE) {
        VerifiableCredential storage cred = credentials[credentialId];
        require(cred.issuer == msg.sender, "Not the issuer of this credential");
        require(cred.status == CredentialStatus.ACTIVE, "Credential not active");

        cred.status = CredentialStatus.REVOKED;

        emit CredentialRevoked(credentialId, msg.sender);
    }

    /**
     * @dev Verify a credential's validity
     */
    function verifyCredential(bytes32 credentialId) external view returns (bool) {
        VerifiableCredential storage cred = credentials[credentialId];

        return (
            cred.status == CredentialStatus.ACTIVE &&
            cred.expirationDate > block.timestamp
        );
    }

    /**
     * @dev Get credentials for a DID
     */
    function getCredentials(address did) external view returns (bytes32[] memory) {
        return identities[did].credentials;
    }

    /**
     * @dev Get credential details
     */
    function getCredential(bytes32 credentialId) external view returns (
        bytes32 id,
        address subject,
        CredentialType credType,
        string memory ipfsHash,
        address issuer,
        uint256 issuanceDate,
        uint256 expirationDate,
        CredentialStatus status
    ) {
        VerifiableCredential storage cred = credentials[credentialId];
        return (
            cred.id,
            cred.subject,
            cred.credType,
            cred.ipfsHash,
            cred.issuer,
            cred.issuanceDate,
            cred.expirationDate,
            cred.status
        );
    }
}

contracts/InvestmentManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "./ProjectFactory.sol";

/**
 * @title InvestmentManager
 * @dev Manages investments in farming projects
 */
contract InvestmentManager is AccessControl, ReentrancyGuard {
    using Counters for Counters.Counter;

    // Role definitions
    bytes32 public constant INVESTOR_ROLE = keccak256("INVESTOR_ROLE");

    // Investment structure
    struct Investment {
        address investor;
        uint256 projectId;
        uint256 amount;
        uint256 timestamp;
        bool claimed;
    }

    // State variables
    ProjectFactory public projectFactory;
    mapping(uint256 => Investment[]) public projectInvestments; // projectId => Investment[]
    mapping(address => uint256[]) public investorProjects; // investor => projectId[]
    mapping(address => mapping(uint256 => uint256)) public investorProjectAmount; // investor => projectId => amount

    // Events
    event Invested(address indexed investor, uint256 indexed projectId, uint256 amount);
    event Withdrawn(address indexed investor, uint256 indexed projectId, uint256 amount);

    constructor(address _projectFactoryAddress) {
        require(_projectFactoryAddress != address(0), "Invalid project factory address");
        projectFactory = ProjectFactory(_projectFactoryAddress);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    /**
     * @dev Invest in a project
     * @param projectId ID of the project to invest in
     */
    function invest(uint256 projectId) external payable nonReentrant onlyRole(INVESTOR_ROLE) {
        require(msg.value > 0, "Investment amount must be greater than 0");

        // Get project details from ProjectFactory
        (bool success, bytes memory data) = address(projectFactory).staticcall(
            abi.encodeWithSignature("getProject(uint256)", projectId)
        );
        require(success, "Failed to fetch project details");

        ProjectFactory.Project memory project = abi.decode(data, (ProjectFactory.Project));

        require(project.status == ProjectFactory.ProjectStatus.Approved, "Project not available for investment");
        require(project.fundedAmount + msg.value <= project.targetAmount, "Investment exceeds target amount");

        // Update project funding
        project.fundedAmount += msg.value;

        // Create new investment
        Investment memory newInvestment = Investment({
            investor: msg.sender,
            projectId: projectId,
            amount: msg.value,
            timestamp: block.timestamp,
            claimed: false
        });

        projectInvestments[projectId].push(newInvestment);

        // Update investor's project list if not already invested
        if (investorProjectAmount[msg.sender][projectId] == 0) {
            investorProjects[msg.sender].push(projectId);
        }

        investorProjectAmount[msg.sender][projectId] += msg.value;

        emit Invested(msg.sender, projectId, msg.value);
    }

    /**
     * @dev Get investments by project ID
     * @param projectId ID of the project
     * @return Array of investments in the project
     */
    function getProjectInvestments(uint256 projectId) external view returns (Investment[] memory) {
        return projectInvestments[projectId];
    }

    /**
     * @dev Get investor's projects
     * @param investor Address of the investor
     * @return Array of project IDs the investor has invested in
     */
    function getInvestorProjects(address investor) external view returns (uint256[] memory) {
        return investorProjects[investor];
    }

    /**
     * @dev Get investor's total investment in a project
     * @param investor Address of the investor
     * @param projectId ID of the project
     * @return Total amount invested
     */
    function getInvestorProjectInvestment(address investor, uint256 projectId) external view returns (uint256) {
        return investorProjectAmount[investor][projectId];
    }

    // Additional functions for project completion and fund distribution will be added in YieldDistributor
}

contracts/OracleIntegration.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "./ProjectFactory.sol";

/**
 * @title OracleIntegration
 * @dev Handles verification of project milestones and data from multiple sources
 */
contract OracleIntegration is AccessControl {
    // Role definitions
    bytes32 public constant ORACLE_NODE = keccak256("ORACLE_NODE");
    bytes32 public constant NGO_AGENT = keccak256("NGO_AGENT");

    // Data source types
    enum DataSource { NGO, IOT, SATELLITE, CHAINLINK }

    // Verification status
    enum VerificationStatus { Pending, Verified, Rejected, Disputed }

    // Milestone structure
    struct Milestone {
        uint256 projectId;
        uint256 milestoneId;
        string description;
        uint256 targetDate;
        uint256 completionDate;
        VerificationStatus status;
        string ipfsHash; // For supporting documents
        address verifiedBy;
        DataSource source;
    }

    // State variables
    ProjectFactory public projectFactory;
    uint256 public verificationThreshold = 2; // Number of verifications required
    mapping(uint256 => Milestone[]) public projectMilestones; // projectId => Milestone[]
    mapping(bytes32 => address[]) public milestoneVerifiers; // milestoneHash => verifierAddresses[]

    // Events
    event MilestoneAdded(uint256 indexed projectId, uint256 milestoneId, string description);
    event MilestoneVerified(uint256 indexed projectId, uint256 milestoneId, address verifier, DataSource source);
    event MilestoneStatusUpdated(uint256 indexed projectId, uint256 milestoneId, VerificationStatus status);
    event DisputeRaised(uint256 indexed projectId, uint256 milestoneId, address raisedBy);

    constructor(address _projectFactoryAddress) {
        require(_projectFactoryAddress != address(0), "Invalid project factory address");
        projectFactory = ProjectFactory(_projectFactoryAddress);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    /**
     * @dev Add a new milestone to a project (only callable by project owner or admin)
     */
    function addMilestone(
        uint256 projectId,
        string memory description,
        uint256 targetDate,
        string memory ipfsHash
    ) external {
        // Verify sender is project owner or admin
        (bool success, bytes memory data) = address(projectFactory).staticcall(
            abi.encodeWithSignature("getProject(uint256)", projectId)
        );
        require(success, "Failed to fetch project details");

        ProjectFactory.Project memory project = abi.decode(data, (ProjectFactory.Project));
        require(
            project.farmer == msg.sender || hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Not authorized to add milestone"
        );

        uint256 milestoneId = projectMilestones[projectId].length;

        projectMilestones[projectId].push(Milestone({
            projectId: projectId,
            milestoneId: milestoneId,
            description: description,
            targetDate: targetDate,
            completionDate: 0,
            status: VerificationStatus.Pending,
            ipfsHash: ipfsHash,
            verifiedBy: address(0),
            source: DataSource.NGO // Default source
        }));

        emit MilestoneAdded(projectId, milestoneId, description);
    }

    /**
     * @dev Verify a milestone (callable by oracle nodes or NGO agents)
     */
    function verifyMilestone(
        uint256 projectId,
        uint256 milestoneId,
        bool isVerified,
        DataSource source
    ) external onlyRole(ORACLE_NODE) {
        require(projectId < projectMilestones[projectId].length, "Milestone does not exist");
        Milestone storage milestone = projectMilestones[projectId][milestoneId];

        require(
            milestone.status == VerificationStatus.Pending ||
            milestone.status == VerificationStatus.Disputed,
            "Milestone already processed"
        );

        // Record verification
        bytes32 milestoneHash = keccak256(abi.encodePacked(projectId, milestoneId));
        milestoneVerifiers[milestoneHash].push(msg.sender);

        emit MilestoneVerified(projectId, milestoneId, msg.sender, source);

        // Check if enough verifications are received
        if (milestoneVerifiers[milestoneHash].length >= verificationThreshold) {
            milestone.status = isVerified ? 
                VerificationStatus.Verified : 
                VerificationStatus.Rejected;
            milestone.completionDate = block.timestamp;
            milestone.verifiedBy = msg.sender;
            milestone.source = source;

            emit MilestoneStatusUpdated(projectId, milestoneId, milestone.status);
        }
    }

    /**
     * @dev Raise a dispute for a milestone
     */
    function raiseDispute(uint256 projectId, uint256 milestoneId) external {
        require(projectId < projectMilestones[projectId].length, "Milestone does not exist");
        Milestone storage milestone = projectMilestones[projectId][milestoneId];

        require(
            milestone.status == VerificationStatus.Verified ||
            milestone.status == VerificationStatus.Rejected,
            "Cannot dispute pending milestone"
        );

        milestone.status = VerificationStatus.Disputed;
        emit DisputeRaised(projectId, milestoneId, msg.sender);
    }

    /**
     * @dev Get all milestones for a project
     */
    function getProjectMilestones(uint256 projectId) external view returns (Milestone[] memory) {
        return projectMilestones[projectId];
    }

    /**
     * @dev Update verification threshold (admin only)
     */
    function setVerificationThreshold(uint256 _threshold) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_threshold > 0, "Threshold must be greater than 0");
        verificationThreshold = _threshold;
    }
}

